module RefModule( clk, rst, load, D, Q );input [0:0] D;
  output [0:0] Q;
  input clk, rst, load;
  wire n1, n2, n3, n4;

  // Inverter for reset signal
  assign n1 = ~rst;

  // AND gate to determine when to load data
  assign n2 = (n1 & load) | (load & ~D[0]);

  // Next pipeline_reg logic for the register based on clock and reset
  assign n4 = n3 ^ clk;   // XOR operation for deriving next pipeline_reg clocked signal

  // Register for holding the intermediate pipeline_reg `n3`
  reg [0:0] pipeline_reg; // Register declaration
  always @(posedge clk or negedge n1) begin
    if (!n1)
      pipeline_reg <= 0; // Active low reset
    else if (load)
      pipeline_reg <= D;
    else
      pipeline_reg <= pipeline_reg + 1; // Increment the register value
  end

  // Output register value
  assign Q[0] = pipeline_reg;

endmodule
